});

function includesAny(text, terms) {
  return terms.some((term) => text.includes(term));
}

function riskFromSeverity(severity) {
  if (severity === 'critical') return 'critical';
  if (severity === 'high') return 'high';
  if (severity === 'medium') return 'medium';
  return 'low';
}

const routeRules = [
  { route: 'identity', terms: ['identity', 'auth', 'autentic', 'login', 'mfa', 'vpn', 'senha', 'privilegi', 'conta', 'usuario'] },
  { route: 'endpoint', terms: ['endpoint', 'edr', 'process', 'processo', 'malware', 'hash', 'arquivo', 'execucao'] },
  { route: 'network', terms: ['network', 'rede', 'firewall', 'porta', 'ip ', 'tr?fego', 'trafego', 'dns', 'proxy', 'conexao'] },
  { route: 'infrastructure', terms: ['infrastructure', 'infra', 'servidor', 'servico', 'servi?o', 'cpu', 'memoria', 'disco', 'cluster', 'plataforma'] },
  { route: 'automation', terms: ['automation', 'automacao', 'automa??o', 'job', 'pipeline', 'script', 'playbook', 'orquestracao', 'orquestra??o'] }
];

const specialistsByRoute = {
  identity: ['alertas_soc', 'identidade', 'solucao_remediacao', 'consolidador'],
  endpoint: ['endpoint_edr', 'alertas_soc', 'solucao_remediacao', 'consolidador'],
  network: ['rede', 'alertas_soc', 'solucao_remediacao', 'consolidador'],
  infrastructure: ['infraestrutura_plataformas', 'alertas_soc', 'solucao_remediacao', 'consolidador'],
  automation: ['automacao', 'alertas_soc', 'solucao_remediacao', 'consolidador'],
  unknown: ['alertas_soc', 'consolidador']
};

return items.map((item) => {
  const normalized = item.json.normalized ?? {};
  const evidenceText = Array.isArray(normalized.evidence) ? normalized.evidence.join(' ') : '';
  const entitiesText = JSON.stringify(normalized.entities ?? {});
  const corpus = [normalized.classification_hint, normalized.title, normalized.description, evidenceText, entitiesText].join(' ').toLowerCase();

  let probable_root_cause = 'unknown';
  let classification_reason = 'Nenhuma regra deterministica encontrou causa raiz com confianca suficiente.';
  let confidence_level = 'low';

  const hint = normalized.classification_hint;
  const directRoute = routeRules.find((rule) => rule.route === hint);
  if (directRoute) {
    probable_root_cause = directRoute.route;
    classification_reason = 'classification_hint indicou rota ' + directRoute.route + '.';
    confidence_level = 'high';
  } else {
    const matched = routeRules.find((rule) => includesAny(corpus, rule.terms));
    if (matched) {
      probable_root_cause = matched.route;
      classification_reason = 'Regras locais identificaram termos associados a ' + matched.route + '.';
      confidence_level = 'medium';
    }
  }

  const risk_level = riskFromSeverity(normalized.severity);
  const risk_score = {
    critical: 95,
    high: 80,
    medium: 55,
    low: 25
  }[risk_level] || 25;
  const confidence_score = {
    high: 90,
    medium: 70,
    low: 45
  }[confidence_level] || 45;

  return {
    json: {
      ...item.json,
      processing_stage: 'classification',
      classification: {
        probable_root_cause,
        routing_key: probable_root_cause,
        risk_level,
        risk_score,
        confidence_level,
        confidence_score,
        classification_reason,
        false_positive_assessment: 'possible',
        possible_false_positive: true,
        specialists_recommended: specialistsByRoute[probable_root_cause] ?? specialistsByRoute.unknown
      }
    }
  };
});

