    user: normalized.entities?.user || null,
    host: normalized.entities?.host || null,
    process: normalized.entities?.process || null,
    ioc: normalized.entities?.ioc || normalized.entities?.file_hash || normalized.entities?.rule_id || null,
    ticket: normalized.entities?.ticket || normalized.case_id || null,
    previous_event: normalized.evidence?.[0] || null
  };

  const output = {
