    workflow_name: workflowName,
    workflow_version: workflowVersion,
    correlation_id: correlationId,
    trace_id: normalized.trace_id || rejection?.trace_id || 'not_available',
    case_id: normalized.case_id || rejection?.case_id || 'not_available',
    status,
    execution_status: status,
    input_type: normalized.input_type || 'not_available',
    severity: normalized.severity || 'not_available',
    probable_root_cause: classification.probable_root_cause,
    risk_level: classification.risk_level,
    risk_score: classification.risk_score,
    confidence_level: classification.confidence_level,
    confidence_score: classification.confidence_score,
    diagnosis: blocked ? rejection?.reason : (specialist?.diagnosis ?? 'Diagnostico especializado nao produzido.'),
    solution_recommendation: finalRecommendation,
    technical_steps: specialist?.technical_steps ?? [],
    escalation: specialist?.escalation ?? 'Revisao humana obrigatoria antes de qualquer acao.',
    observability: {
      execution_id: executionId,
      workflow_version: workflowVersion,
      processing_time_ms,
      correlation_id: correlationId,
      trace_id: normalized.trace_id || 'not_available'
    },
    audit_timestamp: now.toISOString(),
    audit_summary: 'Workflow production ready; audit trail prepared for persistence, SIEM sync, ticketing, cache and manual approval governance.',
    human_approval: {
      required: true,
      required_for_actions: specialist?.critical_actions_need_approval ?? [],
      approval_status: 'pending_human_review'
    },
    correlation,
    security_notes: {
      external_calls_allowed: controls.external_calls_allowed === true,
      remediation_allowed: controls.remediation_allowed === true,
      credentials_allowed: controls.credentials_allowed === true,
      production_allowed: controls.production_allowed === true,
      human_approval_required: true,
      automated_action_executed: false
    },
    validation,
    rejection,
    classification,
    specialist_analysis: specialist,
    integration_targets: {
      siem: process.env.SIEM_BASE_URL ? 'configured_by_env' : 'needs_env',
      ticketing: process.env.TICKETING_BASE_URL ? 'configured_by_env' : 'needs_env',
      cmdb: process.env.CMDB_BASE_URL ? 'configured_by_env' : 'needs_env',
      postgres: 'configured_by_credential',
      redis: 'configured_by_credential'
    }
  };

  return {
    json: {
      case_id: output.case_id,
      trace_id: output.trace_id,
      output_ready_for_human_review: true,
      soc_octopus_output: output
    }
  };
});

